member.example:
For example:

var instanceToExecute = "calleeTestInstance";
var resultPort = Prime.Base.ServiceStore<ITestProgramService>.Service.ExecuteInstanceName(instanceToExecute, $"{instanceToExecute}_firstTime", contextSession);
Prime.Base.ServiceStore<IConsoleService>.Service.Print($"TestInstance=[{instanceToExecute}] exited port=[{resultPort}] on its first execution");
resultPort = Prime.Base.ServiceStore<ITestProgramService>.Service.ExecuteInstanceName(instanceToExecute, $"{instanceToExecute}_secondTime", contextSession);
Prime.Base.ServiceStore<IConsoleService>.Service.Print($"TestInstance=[{instanceToExecute}] exited port=[{resultPort}] on its second execution");
